const topic = $.input.interviewTopic;
const name = $.input.intervieweeName;
const numQ = $.input.numberOfQuestions || 5;
const responses = $.input.intervieweeResponses;

let prompt = 'You are a skilled interviewer. Conduct a structured interview and evaluate the responses.\n\n';
prompt += 'INTERVIEW TOPIC/ROLE: ' + topic + '\n';
prompt += 'INTERVIEWEE: ' + name + '\n';
prompt += 'NUMBER OF QUESTIONS: ' + numQ + '\n\n';

if (responses === 'generate-sample') {
  prompt += 'MODE: Generate sample questions AND realistic sample responses for demonstration.\n\n';
} else {
  prompt += 'INTERVIEWEE RESPONSES:\n' + responses + '\n\n';
}

prompt += 'INSTRUCTIONS:\n';
prompt += '- Generate ' + numQ + ' targeted interview questions for the topic\n';
prompt += '- For each question, evaluate the response on a 1-10 scale\n';
prompt += '- Provide constructive feedback for each answer\n';
prompt += '- Generate follow-up questions based on the responses\n';
prompt += '- Provide an overall interview assessment\n';
prompt += '- Include strengths and areas for improvement\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "interviewee": "' + name + '",\n';
prompt += '  "topic": "' + topic + '",\n';
prompt += '  "date": "YYYY-MM-DD",\n';
prompt += '  "questions": [\n';
prompt += '    {\n';
prompt += '      "questionNumber": 1,\n';
prompt += '      "question": "the interview question",\n';
prompt += '      "response": "the interviewee response",\n';
prompt += '      "score": 7,\n';
prompt += '      "feedback": "evaluation feedback",\n';
prompt += '      "followUp": "suggested follow-up question"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "overallScore": 7.5,\n';
prompt += '  "strengths": ["strength 1", "strength 2"],\n';
prompt += '  "improvements": ["area 1", "area 2"],\n';
prompt += '  "recommendation": "hire|consider|pass",\n';
prompt += '  "summary": "overall assessment summary"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiInterview.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { interviewee: $.input.intervieweeName, topic: $.input.interviewTopic, questions: [], overallScore: 0, strengths: [], improvements: [], recommendation: 'unknown', summary: raw }; }

const ai = $.steps.parseAI.output;
const questions = ai.questions || [];

const header = ['Interviewee', 'Topic', 'Date', 'Q#', 'Question', 'Response', 'Score', 'Feedback', 'Follow-Up'];
const rows = questions.map(q => [
  ai.interviewee || 'Unknown',
  ai.topic || 'Unknown',
  ai.date || new Date().toISOString().slice(0, 10),
  String(q.questionNumber || 0),
  q.question || '',
  q.response || '',
  String(q.score || 0),
  q.feedback || '',
  q.followUp || ''
]);

const summaryRow = [
  ai.interviewee || 'Unknown',
  ai.topic || 'Unknown',
  ai.date || new Date().toISOString().slice(0, 10),
  'SUMMARY',
  'Overall Score: ' + (ai.overallScore || 0) + '/10',
  'Recommendation: ' + (ai.recommendation || 'N/A'),
  String(ai.overallScore || 0),
  'Strengths: ' + (ai.strengths || []).join('; '),
  'Improvements: ' + (ai.improvements || []).join('; ')
];

const allRows = [header].concat(rows).concat([summaryRow]);
return { values: allRows, questionCount: questions.length, overallScore: ai.overallScore || 0, recommendation: ai.recommendation || 'N/A' };
